import{_ as t,o as a,c as o,a3 as i}from"./chunks/framework.BveOjhN0.js";const k=JSON.parse('{"title":"XiHan.Framework.Bot","description":"","frontmatter":{},"headers":[],"relativePath":"cosmos/framework/packages/bot.md","filePath":"cosmos/framework/packages/bot.md","lastUpdated":1783216089000}'),d={name:"cosmos/framework/packages/bot.md"};function s(r,e,l,n,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="xihan-framework-bot" tabindex="-1">XiHan.Framework.Bot <a class="header-anchor" href="#xihan-framework-bot" aria-label="Permalink to &quot;XiHan.Framework.Bot&quot;">​</a></h1><blockquote><p>机器人核心：多平台消息接入的统一抽象</p></blockquote><ul><li><strong>NuGet</strong>：<code>XiHan.Framework.Bot</code></li><li><strong>模块类</strong>：<code>XiHanBotModule</code></li><li><strong>所在层</strong>：基础设施层</li></ul><h2 id="这是什么" tabindex="-1">这是什么 <a class="header-anchor" href="#这是什么" aria-label="Permalink to &quot;这是什么&quot;">​</a></h2><p>这个包是「机器人 / 消息通知」的核心抽象与调度内核。它定义了统一的消息模型、提供者（Provider）抽象、调度器、策略与管道，让你用一致的方式往多个渠道（邮件、短信、Telegram、钉钉、飞书、企业微信……）发消息。核心包本身不含任何具体通道——各通道由独立子包以 <code>UseXxx</code> 扩展方法接入，本包负责编排它们。</p><h2 id="何时使用" tabindex="-1">何时使用 <a class="header-anchor" href="#何时使用" aria-label="Permalink to &quot;何时使用&quot;">​</a></h2><ul><li>需要向多个平台统一发送通知，且希望调用方只面对一个 <code>IBotClient</code></li><li>需要广播 / 主备 / 优先级等发送策略，或重试、限流、环境过滤等横切能力</li><li>需要按模板渲染消息（<code>SendTemplateAsync</code>），或延迟 / 批量发送</li><li>想让「往哪些渠道发」与「用哪个厂商」解耦，通过渠道映射灵活配置</li></ul><h2 id="安装" tabindex="-1">安装 <a class="header-anchor" href="#安装" aria-label="Permalink to &quot;安装&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dotnet</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> package</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> XiHan.Framework.Bot</span></span></code></pre></div><h2 id="启用" tabindex="-1">启用 <a class="header-anchor" href="#启用" aria-label="Permalink to &quot;启用&quot;">​</a></h2><div class="language-csharp vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">csharp</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">DependsOn</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">typeof</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanBotModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">))]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">public</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> class</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> MyModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> : </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">XiHanModule</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { }</span></span></code></pre></div><p>模块在 <code>ConfigureServices</code> 里调用 <code>AddXiHanBot</code>，注册调度器、策略与管道。核心包只提供内核；具体通道通过 <code>BotBuilder</code> 的 <code>UseEmail</code> / <code>UseSms</code> / <code>UseTelegram</code> 等扩展方法（由各子包提供）接入。</p><h2 id="核心能力" tabindex="-1">核心能力 <a class="header-anchor" href="#核心能力" aria-label="Permalink to &quot;核心能力&quot;">​</a></h2><ul><li><strong>统一客户端入口</strong>：<code>IBotClient</code> 提供发送 / 指定渠道发送 / 模板发送 / 批量发送 / 延迟发送，返回 <code>BotDispatchResult</code>（整体成败 + 各提供者明细）</li><li><strong>提供者抽象</strong>：<code>IBotProvider</code> 定义「一个通道怎么发一条消息」，各子包实现它并以 <code>TryAddEnumerable</code> 注册，可多提供者共存</li><li><strong>调度器</strong>：<code>BotDispatcher</code> 解析渠道 → 选提供者 → 应用管道 → 执行策略，统一聚合结果</li><li><strong>发送策略</strong>：<code>Broadcast</code>（广播全部）、<code>Failover</code>（主备，成功即止）、<code>Priority</code>（仅发第一个），由 <code>BotStrategyNames</code> 定义</li><li><strong>横切管道</strong>：重试（<code>RetryPipeline</code>）、限流（<code>RateLimitPipeline</code>）、环境过滤（<code>EnvironmentFilterPipeline</code>），经 <code>XiHanBotOptions</code> 开关配置</li><li><strong>渠道映射</strong>：<code>BotChannel</code> 把逻辑渠道名映射到一组提供者，<code>BotBuilder.AddChannel</code> 登记</li><li><strong>消息模板</strong>：<code>IBotTemplateEngine</code> + <code>BotTemplate</code> 支持按模板名渲染消息（<code>BotMessageType</code> 覆盖 Text / Markdown / Card / Image / File / Link）</li></ul><h2 id="主要类型" tabindex="-1">主要类型 <a class="header-anchor" href="#主要类型" aria-label="Permalink to &quot;主要类型&quot;">​</a></h2><table tabindex="0"><thead><tr><th>类型</th><th>说明</th></tr></thead><tbody><tr><td><code>IBotClient</code></td><td>机器人客户端入口（发送 / 模板 / 批量 / 延迟）</td></tr><tr><td><code>IBotProvider</code></td><td>通道提供者抽象（各子包实现）</td></tr><tr><td><code>BotDispatcher</code></td><td>调度器（渠道解析 + 策略 + 管道编排）</td></tr><tr><td><code>BotDispatchResult</code> / <code>BotResult</code></td><td>调度聚合结果 / 单提供者结果</td></tr><tr><td><code>BotMessage</code> / <code>BotMessageType</code></td><td>消息模型 / 消息类型枚举</td></tr><tr><td><code>IBotStrategy</code> / <code>BotStrategyNames</code></td><td>发送策略抽象与内置策略名（Broadcast/Failover/Priority）</td></tr><tr><td><code>IBotPipeline</code></td><td>横切管道抽象（重试 / 限流 / 环境过滤）</td></tr><tr><td><code>BotBuilder</code></td><td>Bot 构建器（配置选项 / 渠道 / 模板；子包在其上加 <code>UseXxx</code>）</td></tr><tr><td><code>XiHanBotOptions</code></td><td>Bot 配置项（默认策略、重试、限流、环境过滤等）</td></tr><tr><td><code>IBotTemplateEngine</code> / <code>BotTemplate</code></td><td>模板引擎抽象与模板</td></tr></tbody></table><h2 id="依赖模块" tabindex="-1">依赖模块 <a class="header-anchor" href="#依赖模块" aria-label="Permalink to &quot;依赖模块&quot;">​</a></h2><ul><li><a href="./http">XiHan.Framework.Http</a>（通道适配的 HTTP 调用基础）</li><li><a href="./templating">XiHan.Framework.Templating</a>（消息模板渲染）</li><li>无第三方 SDK 依赖；具体平台 SDK 由各通道子包引入</li></ul><h2 id="相关模块" tabindex="-1">相关模块 <a class="header-anchor" href="#相关模块" aria-label="Permalink to &quot;相关模块&quot;">​</a></h2><ul><li><a href="./bot-email">XiHan.Framework.Bot.Email</a></li><li><a href="./bot-sms">XiHan.Framework.Bot.Sms</a></li><li><a href="./bot-telegram">XiHan.Framework.Bot.Telegram</a></li><li><a href="./bot-dingtalk">XiHan.Framework.Bot.DingTalk</a> · <a href="./bot-lark">XiHan.Framework.Bot.Lark</a> · <a href="./bot-wecom">XiHan.Framework.Bot.WeCom</a></li></ul>`,20)])])}const g=t(d,[["render",s]]);export{k as __pageData,g as default};
